export function check_incorrect_fail_use(error) {
	return error instanceof ActionFailure
		? new Error('Cannot "throw fail()". Use "return fail()"')
		: error;
}

export function has_server_load(node) {
	return node.server?.load !== undefined || node.server?.trailingSlash !== undefined;
}

function allow_nodejs_console_log(url) {
	if (!BROWSER) {
		// @ts-ignore
		url[Symbol.for('nodejs.util.inspect.custom')] = (_depth, opts, inspect) => {
			return inspect(new URL(url), opts);
		};
	}
}

setContext("carbon:CheckboxGroup", {
  selectedValues,
  groupName: readOnly(groupName),
  groupRequired: readOnly(groupRequired),
  readonly: readOnly(groupReadonly),
  update,
});

function assignStyle(el: HTMLElement | null | undefined, style: Partial<CSSStyleDeclaration>) {
	if (!el) return;
	const previousStyle = el.style.cssText;
	Object.assign(el.style, style);
	return () => {
		el.style.cssText = previousStyle;
	};
}

export function teardown(fn) {
	const effect = create_effect(RENDER_EFFECT, null);
	set_signal_status(effect, CLEAN);
	effect.teardown = fn;
	return effect;
}

if (size !== undefined)
    // svelte-ignore reactive_declaration_non_reactive_property
    dispatch("change", { size, breakpointValue: breakpoints[size] });

const shouldContinue = dispatch(
  "close",
  { timeout: closeFromTimeout === true },
  { cancelable: true },
);

